import{_ as e,a as d,b as a,c as o,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as l,c as n,a2 as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Dropbox 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/dropbox.md","filePath":"cn/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"cn/upload/dropbox.md"};function h(b,t,x,u,m,f){return l(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="dropbox-渠道添加说明" tabindex="-1">Dropbox 渠道添加说明 <a class="header-anchor" href="#dropbox-渠道添加说明" aria-label="Permalink to &quot;Dropbox 渠道添加说明&quot;">​</a></h1><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>一个 Dropbox 账号</td><td>用来登录 Dropbox 并授权应用</td></tr><tr><td>一个 Dropbox 应用</td><td>用来生成 <code>App Key</code> 和 <code>App Secret</code></td></tr><tr><td>当前图床访问域名</td><td>用来配置授权回调地址</td></tr><tr><td>一个可用的 Dropbox 空间</td><td>后面真正存图用</td></tr></tbody></table><h2 id="添加步骤" tabindex="-1">添加步骤 <a class="header-anchor" href="#添加步骤" aria-label="Permalink to &quot;添加步骤&quot;">​</a></h2><h3 id="第一步-创建-dropbox-应用" tabindex="-1">第一步：创建 Dropbox 应用 <a class="header-anchor" href="#第一步-创建-dropbox-应用" aria-label="Permalink to &quot;第一步：创建 Dropbox 应用&quot;">​</a></h3><ol><li>打开 Dropbox App Console：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>点击创建新应用。</li><li>访问类型建议选：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>给应用起一个你自己能认出来的名字，例如 <code>imgbed-app</code>。</li><li>创建完成后进入应用详情页。</li></ol><p>这一步要特别注意：</p><table tabindex="0"><thead><tr><th>访问类型</th><th>建议</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>推荐，和当前项目最匹配</td></tr><tr><td><code>Full Dropbox</code></td><td>不建议，权限更大，当前项目没必要</td></tr></tbody></table><p><img src="'+e+'" alt="开发者创建应用" loading="lazy"></p><h3 id="第二步-配置回调地址" tabindex="-1">第二步：配置回调地址 <a class="header-anchor" href="#第二步-配置回调地址" aria-label="Permalink to &quot;第二步：配置回调地址&quot;">​</a></h3><p>在 Dropbox 应用详情页里找到 OAuth 或 Redirect URI 配置，填下面这个地址：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的域名/api/oauth/dropbox/callback</span></span></code></pre></div><p>如果你平时会从多个域名打开后台，就把多个域名对应的回调都加上。</p><p><img src="'+d+'" alt="配置回调地址" loading="lazy"></p><h3 id="第三步-配置应用权限-scopes" tabindex="-1">第三步：配置应用权限（Scopes） <a class="header-anchor" href="#第三步-配置应用权限-scopes" aria-label="Permalink to &quot;第三步：配置应用权限（Scopes）&quot;">​</a></h3><p>进入应用详情页的 <code>Permissions</code> 标签页，至少勾选下面这些权限：</p><table tabindex="0"><thead><tr><th>权限</th><th>是否必须</th><th>用途</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>必须</td><td>查询账号基础信息、容量信息</td></tr><tr><td><code>files.metadata.read</code></td><td>必须</td><td>读取文件/目录元数据（用于路径检查）</td></tr><tr><td><code>files.metadata.write</code></td><td>必须</td><td>创建目录等元数据写操作</td></tr><tr><td><code>files.content.write</code></td><td>必须</td><td>上传文件（缺少会报 <code>required scope &#39;files.content.write&#39;</code>）</td></tr><tr><td><code>files.content.read</code></td><td>建议</td><td>下载、预览、临时直链等读文件能力</td></tr></tbody></table><p>勾选后点击页面底部 <code>Submit</code> 提交权限变更。</p><p><img src="'+a+'" alt="添加对应的权限" loading="lazy"></p><p>重要说明：</p><table tabindex="0"><thead><tr><th>场景</th><th>处理方式</th></tr></thead><tbody><tr><td>你修改了 Scopes</td><td>必须重新走一次“获取令牌”流程，拿新的 <code>Refresh Token</code></td></tr><tr><td>没有重新授权</td><td>旧 token 不会自动获得新权限，上传仍会失败</td></tr></tbody></table><h3 id="第四步-记录应用信息" tabindex="-1">第四步：记录应用信息 <a class="header-anchor" href="#第四步-记录应用信息" aria-label="Permalink to &quot;第四步：记录应用信息&quot;">​</a></h3><p>应用创建完成后，记下这两个值：</p><table tabindex="0"><thead><tr><th>Dropbox 后台字段</th><th>后面填到哪里</th></tr></thead><tbody><tr><td><code>App key</code></td><td>系统里的 <code>App Key</code></td></tr><tr><td><code>App secret</code></td><td>系统里的 <code>App Secret</code></td></tr></tbody></table><h3 id="第五步-回系统里填写-dropbox-渠道" tabindex="-1">第五步：回系统里填写 Dropbox 渠道 <a class="header-anchor" href="#第五步-回系统里填写-dropbox-渠道" aria-label="Permalink to &quot;第五步：回系统里填写 Dropbox 渠道&quot;">​</a></h3><p>在上传设置里选择 <code>Dropbox</code> 后，按下面这套填：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>你该填什么</th></tr></thead><tbody><tr><td>渠道名称</td><td>你自己起，例如 <code>Dropbox主账号</code></td></tr><tr><td>App Key</td><td>刚才 Dropbox 应用的 <code>App key</code></td></tr><tr><td>App Secret</td><td>刚才 Dropbox 应用的 <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>先留空</td></tr><tr><td>根目录</td><td>可选，默认 <code>imgbed</code></td></tr><tr><td>备注</td><td>可选</td></tr></tbody></table><p><img src="'+o+'" alt="获取令牌" loading="lazy"></p><h3 id="第六步-获取-refresh-token" tabindex="-1">第六步：获取 Refresh Token <a class="header-anchor" href="#第六步-获取-refresh-token" aria-label="Permalink to &quot;第六步：获取 Refresh Token&quot;">​</a></h3><ol><li>在系统里点 <code>获取令牌</code>。</li><li>登录你要绑定的 Dropbox 账号。</li><li>按提示授权。</li><li>授权成功后，回调页会显示一串 <code>Refresh Token</code>。</li><li>复制它。</li><li>回到系统，粘贴到 <code>Refresh Token</code> 输入框里。</li></ol><p><img src="'+r+'" alt="复制令牌" loading="lazy"></p><h2 id="添加完成后怎么检查" tabindex="-1">添加完成后怎么检查 <a class="header-anchor" href="#添加完成后怎么检查" aria-label="Permalink to &quot;添加完成后怎么检查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>检查项</th><th>检查方式</th></tr></thead><tbody><tr><td>渠道卡片是否出现</td><td>保存后页面里能看到 Dropbox 渠道</td></tr><tr><td>渠道是否能启用</td><td>开关能正常打开</td></tr><tr><td>令牌是否已写入</td><td>详情页能看到 <code>Refresh Token</code> 已保存</td></tr><tr><td>上传是否正常</td><td>上传测试图后，Dropbox 应用目录里出现对应文件</td></tr></tbody></table><p>如果开启了容量限制，可以点击查询额度。查询成功后，卡片会显示已用容量、总容量和更新时间。</p><p><img src="'+p+`" alt="查询额度成功" loading="lazy"></p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>处理办法</th></tr></thead><tbody><tr><td>系统提示配置不完整</td><td>检查 <code>App Key</code>、<code>App Secret</code>、<code>Refresh Token</code> 是否都填了</td></tr><tr><td>授权成功但没拿到 <code>Refresh Token</code></td><td>重新点一次 <code>获取令牌</code>，确认走的是离线授权</td></tr><tr><td>上传时报 <code>required scope &#39;files.content.write&#39;</code></td><td>回 Dropbox <code>Permissions</code> 勾选 <code>files.content.write</code>，点 <code>Submit</code> 后重新获取 <code>Refresh Token</code></td></tr><tr><td>回调失败</td><td>检查回调地址是否是 <code>https://你的域名/api/oauth/dropbox/callback</code></td></tr><tr><td>文件找不到</td><td>确认 Dropbox 应用是不是按 <code>App folder</code> 模式创建的</td></tr></tbody></table><h2 id="渠道流程速查" tabindex="-1">渠道流程速查 <a class="header-anchor" href="#渠道流程速查" aria-label="Permalink to &quot;渠道流程速查&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打开 Dropbox App Console</span></span>
<span class="line"><span>-&gt; 创建应用</span></span>
<span class="line"><span>-&gt; 访问类型选 App folder</span></span>
<span class="line"><span>-&gt; 配置回调地址 https://你的域名/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Permissions 勾选 account_info.read / files.metadata.read / files.metadata.write / files.content.write（建议再勾 files.content.read）</span></span>
<span class="line"><span>-&gt; 点击 Submit 提交权限</span></span>
<span class="line"><span>-&gt; 复制 App Key 和 App Secret</span></span>
<span class="line"><span>-&gt; 回系统填 App Key / App Secret</span></span>
<span class="line"><span>-&gt; 点击 获取令牌</span></span>
<span class="line"><span>-&gt; 复制回调页里的 Refresh Token</span></span>
<span class="line"><span>-&gt; 粘回系统保存</span></span></code></pre></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ol><li>Dropbox App Console：<a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide：<a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide：<a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const y=s(c,[["render",h]]);export{_ as __pageData,y as default};
